package chi

import (
	"net/http"
	"net/http/httptest"
	"sync"
	"testing"
	"time"
)

func TestMuxMetricsCollector(t *testing.T) {
	var mu sync.Mutex
	var hits []RouteMetric

	collector := &SimpleMetricsCollector{
		Fn: func(m RouteMetric) {
			mu.Lock()
			defer mu.Unlock()
			hits = append(hits, m)
		},
	}

	r := NewRouter()
	r.SetMetricsCollector(collector)
	r.Get("/users/{id}", func(w http.ResponseWriter, r *http.Request) {
		time.Sleep(1 * time.Millisecond)
		w.WriteHeader(http.StatusOK)
	})

	ts := httptest.NewServer(r)
	defer ts.Close()

	resp, err := http.Get(ts.URL + "/users/42")
	if err != nil {
		t.Fatal(err)
	}
	resp.Body.Close()

	mu.Lock()
	defer mu.Unlock()

	if len(hits) != 1 {
		t.Fatalf("expected 1 recorded hit, got %d", len(hits))
	}

	m := hits[0]
	if m.Pattern != "/users/{id}" {
		t.Errorf("expected pattern /users/{id}, got %q", m.Pattern)
	}
	if m.Method != "GET" {
		t.Errorf("expected method GET, got %q", m.Method)
	}
	if m.Path != "/users/42" {
		t.Errorf("expected path /users/42, got %q", m.Path)
	}
	if m.Duration <= 0 {
		t.Errorf("expected positive duration, got %v", m.Duration)
	}
	if m.URLParams["id"] != "42" {
		t.Errorf("expected url param id=42, got %q", m.URLParams["id"])
	}
}

func TestMuxMetricsCollectorNotConfigured(t *testing.T) {
	r := NewRouter()
	r.Get("/ping", func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusOK)
	})

	ts := httptest.NewServer(r)
	defer ts.Close()

	resp, err := http.Get(ts.URL + "/ping")
	if err != nil {
		t.Fatal(err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		t.Fatalf("expected status 200, got %d", resp.StatusCode)
	}
}

